const yaml = space.utils.yaml.parse(text)
if (yaml && Array.isArray(yaml)) {
  for (const entry of yaml) {
    if (entry && entry.username === "mr_kowalski") entry.full_name = "John Ronald Kowalski"
  }
} else if (yaml && typeof yaml === "object") {
  if (yaml.mr_kowalski && typeof yaml.mr_kowalski === "object") {
    yaml.mr_kowalski.full_name = "John Ronald Kowalski"
  } else if (yaml.contacts && typeof yaml.contacts === "object") {
    if (yaml.contacts.mr_kowalski && typeof yaml.contacts.mr_kowalski === "object") {
      yaml.contacts.mr_kowalski.full_name = "John Ronald Kowalski"
    }
  }
}
return await space.api.fileWrite("~/contacts.yaml", space.utils.yaml.stringify(yaml), "utf8")

